     return {};
   MapVector<PHINode *, VPValue *> ExitingValuesToFix;
-  BasicBlock *ExitBB =
-      cast<VPIRBasicBlock>(MiddleVPBB->getSuccessors()[0])->getIRBasicBlock();
+  // The exit block is the first successor. If there is only one successor, it
+  // is the exit block (no scalar epilogue). If there are two successors, the
