   BasicBlock *ExitingBB = OrigLoop->getExitingBlock();
   for (PHINode &ExitPhi : ExitBB->phis()) {
     Value *IncomingValue =
@@ -8660,13 +8664,9 @@ static MapVector<PHINode *, VPValue *> collectUsersInExitBlock(
